def build_text_rows(texts):
    """Convert text dicts to Python source code rows."""
    lines = []
    for i, t in enumerate(texts):
        lines.append(f"    # {i+1}. {t['title_ru']}")
        lines.append("    {")
        lines.append(f'        "level_id": {t["level_id"]},')
        lines.append(f'        "title_he": {json.dumps(t["title_he"], ensure_ascii=False)},')
        lines.append(f'        "title_ru": {json.dumps(t["title_ru"], ensure_ascii=False)},')
        lines.append(f'        "content_he": {json.dumps(t["content_he"], ensure_ascii=False)},')
        lines.append(f'        "content_ru": {json.dumps(t["content_ru"], ensure_ascii=False)},')
        lines.append(f'        "vocabulary_json": _j({json.dumps(json.loads(t["vocabulary_json"]), ensure_ascii=False)}),')
        lines.append(f'        "audio_url": None,')
        lines.append(f'        "category": {json.dumps(t["category"], ensure_ascii=False)},')
        lines.append("    },")
    return "\n".join(lines)


